const content = $input.item.json.message.content;
let eval;
try {
  const match = content.match(/\{[\s\S]*\}/);
  eval = JSON.parse(match[0]);
} catch(e) {
  eval = { score: 0, adequation_formation: 'moyenne', points_forts: [], points_vigilance: ['Analyse automatique impossible'], recommandation: 'entretien', commentaire: 'À évaluer manuellement' };
}
const c = $('Normaliser et valider').item.json;
const statutMap = { admission_directe: 'admis', entretien: 'entretien', liste_attente: 'liste_attente', refus: 'refuse' };
return { ...c, score: eval.score, adequation: eval.adequation_formation, recommandation: eval.recommandation, statut: statutMap[eval.recommandation] || 'en_evaluation', commentaire_ia: eval.commentaire, points_forts: (eval.points_forts || []).join(' | ') };

